import type { Product } from "../types.js";
import { products } from "../data.js";
import { ServiceError } from "./service-error.js";

export interface ProductListResult {
  products: Product[];
  summary: {
    count: number;
    totalInventoryValue: number;
    averagePrice: number;
  };
}

export interface ProductDetail extends Product {
  isLowStock: boolean;
  inventoryValue: number;
}

export function listProducts(filters: {
  category?: string;
  minPrice?: number;
  maxPrice?: number;
}): ProductListResult {
  let filtered = [...products];

  if (filters.category !== undefined) {
    filtered = filtered.filter((p) => p.category === filters.category);
  }

  if (filters.minPrice !== undefined) {
    filtered = filtered.filter((p) => p.price >= filters.minPrice!);
  }

  if (filters.maxPrice !== undefined) {
    filtered = filtered.filter((p) => p.price <= filters.maxPrice!);
  }

  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice =
    filtered.length > 0
      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
      : 0;

  return {
    products: filtered,
    summary: {
      count: filtered.length,
      totalInventoryValue: Math.round(totalValue * 100) / 100,
      averagePrice: Math.round(avgPrice * 100) / 100,
    },
  };
}

export function getProduct(id: number): ProductDetail | null {
  const product = products.find((p) => p.id === id);
  if (!product) return null;

  return {
    ...product,
    isLowStock: product.stock < 10,
    inventoryValue: Math.round(product.price * product.stock * 100) / 100,
  };
}

export function updateProductStock(
  id: number,
  adjustment: number
): ProductDetail | null {
  const product = products.find((p) => p.id === id);
  if (!product) return null;

  const newStock = product.stock + adjustment;
  if (newStock < 0) {
    throw new ServiceError(400, "Insufficient stock");
  }

  product.stock = newStock;

  return {
    ...product,
    isLowStock: product.stock < 10,
    inventoryValue: Math.round(product.price * product.stock * 100) / 100,
  };
}

